INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (464, 157006, 7, 610, '那不会再回来的昨天系列（1）--中山路', '常常因为某个人的某一句话，我会突然有想写东西的冲动，今天晚上也是因为一句话，我想起了中山路。
<br>
<br>    每年回来一次，回来的第一天，一定会到中山路上去逛，仿佛成了一个约定，和自己的一个约定。厦门的家离中山路不算远，走15分钟的路就到了，所以闲暇时也总是在那里晃，即使没有什么特别要买的东西，也习惯去中山路看看。喜欢路上悠闲的人们，和我一样无所事事，只是随意张望的人，也喜欢听路上人们闲谈时浓浓的乡音，慢慢地走着，心里是满足的。
<br>
<br>    印象中，中山路总是拥挤，古老的牌楼外面总是挂满了霓虹灯，传统与现代的结合，一如厦门这个城市，残酷而温情；或许正因为这样特殊的魅力，我总是流连。习惯走在巴黎春天这边，是左边吧，即使偶尔去新华书店买书，我也会尽量找到个出口到对面去，右边有太多的廉价特卖场和抢购的人群，行人们都是匆匆的，失去了原有的风味。相反的，左边有光合作用书房，有巴黎春天，有麦当劳，都是我喜欢去的，虽然，右边的特卖场偶尔也吸引我，可是新华书店要寄包的规定让我觉得很不习惯，所以渐渐地也不去了。
<br>
<br>    每个地方都有适合它的时间段，中山路，对我而言，它是属于黄昏和夜晚的。在巴黎春天里消磨一个下午，黄昏的时候出来，就可以看见满街温暖的灯光，尤其喜欢商场门口那条行人道，整齐的一式的圆灯，柔柔的光线，让人觉得安全而温暖。我常常凝望橱窗里陈列的时装，幻想几时可以买到其中的一件，即使是幻想，我也觉得很满足，看着玻璃窗里我的影子，就觉得自己不是孤单的。逛街累了，就到麦当劳吃点点心，冬天的下午适合吃猪柳蛋加一杯红茶，坐在二楼的窗边，看经过的人们，热热的汉堡，暖暖的红茶，我对生活的要求一向不高。突然想到红茶里要加奶加糖的，记得有一次跟服务生要奶油球和糖包的时候，那个男生迟疑地对我说：“小姐，我们红茶是不带牛奶和糖的。”我突然觉得一定要加牛奶和糖否则我的那杯红茶白买了！于是我微笑着但是语气冰冷地回答：“我知道。可是我想要一份。谢谢。”可怜的男生，只好心里千万个不愿意地递给我，转过身的时候，我脸上挂着胜利的微笑。。。那天那杯红茶好象特别好喝。。。呵呵。。。偶尔要为生活找点乐趣。吃饱喝足之后，可以到光合作用看看书，我习惯站着，不是不想花钱喝咖啡，而是为了肠胃的消化着想，书还是很多的，我临走之前买了安妮宝贝的文集和小王子，都是隐晦的文字，却是我喜欢的风格。
<br>
<br>    在我看来，左边的中山路适合一个人，因为可以独自享受，右边，最好有一个爱你的人牵着你的手。曾经每天都在中山路上逛，那时的我，左边，右边，都有一个人轻轻地牵着我的手，人群再嘈杂我的心也是安静的。从不一个人走右边，不得以的时候，我总是觉得孤单，曾经喜欢去仙踪林，喜欢那里的“随便”和特色饮料，可是渐渐地也不去了，因为一个人。仙踪林不是为单身人士准备的，可爱的摇椅若对面空空，心也只是空荡，和一个人的麦当劳不同，这里窗外的人群总是寂寞，从没试在这里独坐，想必自己没有那种勇气。也不是完全排斥右边的，至少有人陪我的时候，我还是乐意去那几家COTTON SHOP和BOSSINI逛逛的，喜欢BOSSINI的衬衫，价廉物美，回来之后一直穿着，还很多人说PP呢！可是，右边的中山路仍然装满了我的伤心回忆，再多的廉价衬衫也无法掩盖。
<br>
<br>  一条街，在我心里分成两边，一边是我的小资个人生活，一边是我不愿再面对的伤心回忆，满街的人群都在我的现实与过往之中而不自知，或许我们每天都生活在别人的世界里，在别人的故事里扮演一个匆匆路过的行人，只是背景，那时那刻。。。
<br>
<br>    想念中山路，想念那杯温暖的红茶，想念路上柔和的灯光，想念被保护的感觉，想念拥挤的人群，想念那不会再回来的昨天。。。', '常常因为某个人的某一句话，我会突然有想写东西的冲动，今天晚上也是因为一句话，我想起了中山路。

